sql:
SELECT AVG(close_price) AS avg_close_price, MAX(high_price) AS max_high_price
FROM monthly_prices
WHERE stock_id = 1;

SELECT stock_id, AVG(close_price) AS average_close_price
FROM monthly_prices
GROUP BY stock_id;

SELECT tweet_count, sentiment_score
FROM twitter_sentiment
ORDER BY sentiment_score DESC;

SELECT si 
FROM stock_indicators 
WHERE stock_id = 1 AND date = '2023-08-31';
